// File: com/mycompany/util/MathUtils.java
package com.mycompany.util;

public class MathUtils {
    public static int add(int a, int b) {
        return a + b;
    }

    public static int multiply(int a, int b) {
        return a * b;
    }

    public static int factorial(int n) {
        int result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }
}

// File: com/mycompany/app/Main.java
package com.mycompany.app;

import com.mycompany.util.MathUtils;
// Import entire package: import com.mycompany.util.*;

public class Main {
    public static void main(String[] args) {
        // Using the imported class
        System.out.println("Add: " + MathUtils.add(10, 5));
        System.out.println("Multiply: " + MathUtils.multiply(10, 5));
        System.out.println("Factorial of 5: " + MathUtils.factorial(5));

        // Built-in packages
        // java.lang.* — automatically imported (String, Math, System)
        // java.util.* — Scanner, ArrayList, HashMap
        // java.io.* — File I/O

        java.util.ArrayList<String> list = new java.util.ArrayList<>();
        list.add("Hello");
        list.add("World");
        System.out.println("ArrayList: " + list);

        // Using fully qualified name without import
        java.util.HashMap<String, Integer> map = new java.util.HashMap<>();
        map.put("Key", 42);
        System.out.println("HashMap: " + map);
    }
}

